            setreg = filter_pc(pc, jmptarget);
            eprintln!("DBG   change at pc={} op={:?} → setreg={}", pc, op, setreg);
        }
    }
    eprintln!("DBG find_set_reg EXIT setreg={} effective_lastpc={}", setreg, effective_lastpc);
    setreg
}

