pub fn run_pending_finalizers(state: &mut LuaState) {
    loop {
        let target_idx = {
            let pending = &state.global().pending_finalizers;
            let mut found: Option<usize> = None;
            for (i, t) in pending.iter().enumerate().rev() {
                let sc = std::rc::Rc::strong_count(&t.0);
                eprintln!("DBG run_pending_finalizers: entry {} strong_count={}", i, sc);
                if sc == 1 {
                    found = Some(i);
                    break;
                }
            }
            found
        };
        let Some(i) = target_idx else { break; };
        let tbl = state.global_mut().pending_finalizers.swap_remove(i);
        let mt = tbl.metatable();
        let gc_fn = match mt {
            Some(ref m) => {
                let name = state.global().tmname[crate::tagmethods::TagMethod::Gc as usize].clone();
                m.get_short_str(&name)
            }
            None => LuaValue::Nil,
        };
        if !matches!(gc_fn, LuaValue::Function(_)) {
            continue;
        }
        let sc_before = std::rc::Rc::strong_count(&tbl.0);
        eprintln!("DBG before pcall_k: tbl.strong_count={}", sc_before);
        state.push(gc_fn);
        state.push(LuaValue::Table(tbl.clone()));
        let sc_after_push = std::rc::Rc::strong_count(&tbl.0);
        eprintln!("DBG after push: tbl.strong_count={}", sc_after_push);
        let _ = pcall_k(state, 1, 0, 0, 0, None);
        let sc_after_pcall = std::rc::Rc::strong_count(&tbl.0);
        eprintln!("DBG after pcall: tbl.strong_count={}", sc_after_pcall);
        drop(tbl);
    }
}

